import { ArticleListClient } from './article-list-client';

export default async function ArticlesPage() {
  const articles = await fetchArticles(); // Server-side data fetch

  return (
    <div>
      <h1>Articles</h1>
      <ArticleListClient initialArticles={articles} />
    </div>
